using System.IdentityModel.Tokens.Jwt;
using System.Security.Claims;
using System.Text;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Configuration;

public class JwtMiddleware
{
    private readonly IConfiguration _configuration;

    public JwtMiddleware(IConfiguration configuration)
    {
        _configuration = configuration;
    }

    public async Task Invoke(HttpContext context, Func<Task> next)
    {
        var token = context.Request.Headers["Authorization"].FirstOrDefault()?.Split(" ").LastOrDefault();

        if (token != null)
        {
            try
            {
                var secretKey = Encoding.ASCII.GetBytes(_configuration["JwtSettings:SecretKey"]);
                var tokenHandler = new JwtSecurityTokenHandler();
                var tokenValidationParameters = new TokenValidationParameters
                {
                    ValidateIssuer = false,
                    ValidateAudience = false,
                    ValidateLifetime = true,
                    IssuerSigningKey = new SymmetricSecurityKey(secretKey)
                };

                var validatedToken = tokenHandler.ValidateToken(token, tokenValidationParameters);

                var userId = validatedToken.Claims.First(x => x.Type == ClaimTypes.NameIdentifier).Value;

                context.User = new ClaimsPrincipal(new ClaimsIdentity(new[]
                {
                    new Claim(ClaimTypes.NameIdentifier, userId)
                }));
            }
            catch
            {
                // Handle invalid token
            }
        }

        await next();
    }
}
